import { expect, test } from "vitest";
import * as Evm from "./eth";
// import * as z from "zod";

function sum(a: number, b: number) {
  return a + b;
}

test("adds 1 + 2 to equal 3", () => {
  expect(sum(1, 2)).toBe(3);
});

